// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import org.junit.jupiter.api.Test;

class LmdbFanOutStatsTest {

	@Test
	void estimatesUniformAndHubFanOutInBothDirections() {
		LmdbFanOutStats stats = new LmdbFanOutStats();

		long uniform = 10L;
		for (long subject = 1L; subject <= 1_000L; subject++) {
			stats.recordAdded(subject, uniform, subject * 2L);
			stats.recordAdded(subject, uniform, subject * 2L + 1L);
		}

		long hub = 20L;
		for (long object = 1L; object <= 2_000L; object++) {
			stats.recordAdded(1L, hub, object);
		}

		assertThat(stats.meanFanOut(uniform, true).orElseThrow()).isBetween(1.7, 2.3);
		assertThat(stats.meanFanOut(uniform, false).orElseThrow()).isBetween(0.8, 1.2);
		assertThat(stats.meanFanOut(hub, true).orElseThrow()).isGreaterThan(1_500D);
		assertThat(stats.meanFanOut(hub, false).orElseThrow()).isBetween(0.8, 1.2);
	}

	@Test
	void removalsLowerTheAdvisoryTripleCountWithoutCorruptingTheEstimate() {
		LmdbFanOutStats stats = new LmdbFanOutStats();
		for (long object = 1L; object <= 100L; object++) {
			stats.recordAdded(1L, 30L, object);
		}

		for (long object = 1L; object <= 25L; object++) {
			stats.recordRemoved(1L, 30L, object);
		}

		assertThat(stats.tripleCount(30L)).hasValue(75L);
		assertThat(stats.meanFanOut(30L, true).orElseThrow()).isBetween(70D, 80D);
	}

	@Test
	void boundedTrackerRetainsHeavyPredicates() {
		LmdbFanOutStats stats = new LmdbFanOutStats(2);
		for (int i = 0; i < 20; i++) {
			stats.recordAdded(i, 100L, i);
		}
		for (int i = 0; i < 10; i++) {
			stats.recordAdded(i, 200L, i);
		}
		stats.recordAdded(1L, 300L, 1L);

		assertThat(stats.trackedPredicateCount()).isEqualTo(2);
		assertThat(stats.tripleCount(100L)).hasValue(20L);
		assertThat(stats.tripleCount(200L)).hasValue(10L);
		assertThat(stats.tripleCount(300L)).isEmpty();
	}

	@Test
	void promotedPredicateDoesNotMixHistoricalFrequencyWithFreshDistinctRegisters() {
		LmdbFanOutStats stats = new LmdbFanOutStats(1);
		for (int i = 0; i < 10; i++) {
			stats.recordAdded(i, 100L, i);
		}
		for (int i = 0; i < 20; i++) {
			stats.recordAdded(i, 200L, 1_000L + i);
		}

		assertThat(stats.tripleCount(100L)).isEmpty();
		assertThat(stats.meanFanOut(200L, false).orElseThrow()).isBetween(0.8D, 1.2D);
	}

}
